// Get cart items and user details
const cartItems = $input.all().map(item => item.json);
const userData = $('Split In Batches').item.json;
const emailType = userData.email_to_send;
const firstName = userData.first_name || 'Customer';
const recipientEmail = userData.recipient_email;

// Helper function to format currency
const formatCurrency = (amount) => {
  const num = parseFloat(amount) || 0;
  return '₱' + num.toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
};

// Check if there are valid items (to handle empty dummy item from alwaysOutputData)
const hasValidItems = cartItems && cartItems.length > 0 && cartItems[0].cart_item_id;

if (!hasValidItems) {
  return [{
    json: {
      sendEmail: false,
      userId: userData.user_id,
      emailType: emailType
    }
  }];
}

// Build cart items HTML and text
let itemsHtml = '';
let itemsText = '';
let subtotal = 0;

for (const item of cartItems) {
  const itemName = `${item.cake_size || '4"'} ${item.cake_type || 'Round'}, ${item.cake_thickness || '2 in thickness'}`;
  const qty = item.quantity || 1;
  const price = parseFloat(item.final_price) || 0;
  const itemTotal = price * qty;
  subtotal += itemTotal;

  const imageUrl = item.customized_image_url || item.original_image_url || 'https://cqmhanqnfybyxezhobkx.supabase.co/storage/v1/object/public/cakegenie/placeholder-cake.jpg';
  const flavor = item.customization_details?.flavors?.[0] || item.customization_details?.flavor || 'Custom flavor';

  itemsHtml += `
  <tr>
    <td style="padding: 12px; border-bottom: 1px solid #ddd;">
      <div style="display: flex; align-items: center;">
        <img src="${imageUrl}" alt="Cake design" style="width: 80px; height: 80px; object-fit: cover; border-radius: 8px; margin-right: 12px; display: block;" />
        <div>
          <strong>${itemName}</strong>
          <br><small style="color: #666;">Flavor: ${flavor}</small>
        </div>
      </div>
    </td>
    <td style="padding: 12px; border-bottom: 1px solid #ddd; text-align: center;">${qty}</td>
    <td style="padding: 12px; border-bottom: 1px solid #ddd; text-align: right;">${formatCurrency(price)}</td>
    <td style="padding: 12px; border-bottom: 1px solid #ddd; text-align: right;">${formatCurrency(itemTotal)}</td>
  </tr>`;

  itemsText += `${itemName} x ${qty} - ${formatCurrency(itemTotal)}\n`;
}

// Tailor email copy based on type (100 min vs 18 hour)
const isFirstEmail = emailType === '100_min';
const subject = isFirstEmail 
  ? `✨ We've saved your custom cake design, ${firstName}! ✨`
  : `🎂 Still thinking about your cake, ${firstName}? (We saved your cart!)`;

const headerTitle = isFirstEmail
  ? `Your custom design is waiting!`
  : `Magical celebrations are just a click away!`;

const introductoryCopy = isFirstEmail
  ? `We noticed you left some custom creations in your cart. Your dream cake is still saved and ready for you to complete!`
  : `Don't let your celebrations go without a custom touch! We've saved your custom cake design. Return now to secure your delivery date.`;

// Build HTML email
const htmlContent = `<!DOCTYPE html><html><head><meta charset='UTF-8'><meta name='viewport' content='width=device-width,initial-scale=1.0'><style>body{font-family:Arial,sans-serif;line-height:1.6;color:#333;margin:0;padding:0}.container{max-width:600px;margin:0 auto;padding:0}.logo-header{text-align:center;padding:30px 20px;background:#fff}.logo-header img{max-width:280px;height:auto;display:block;margin:0 auto}.header{background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);color:white;padding:30px;text-align:center;border-radius:10px 10px 0 0}.content{background:#fff;padding:30px;border:1px solid #e0e0e0;border-top:none;border-radius:0 0 10px 10px}.section{margin:20px 0}.section-title{font-size:18px;font-weight:bold;color:#667eea;margin-bottom:10px;border-bottom:2px solid #667eea;padding-bottom:5px}.footer{text-align:center;padding:20px;color:#666;font-size:14px}.btn-primary{display:inline-block;padding:12px 24px;background:#667eea;color:#ffffff !important;text-decoration:none;font-weight:bold;border-radius:8px;margin:20px 0;text-align:center}</style></head><body><div class='container'><div class='logo-header'><img src='https://cqmhanqnfybyxezhobkx.supabase.co/storage/v1/object/public/landingpage/new%20genie%20logo%20long.webp' alt='Genie.ph'></div><div class='header'><h1 style='margin:0;font-size:26px'>${headerTitle}</h1></div><div class='content'><p>Hi <strong>${firstName}</strong>,</p><p>${introductoryCopy}</p><div class='section'><div class='section-title'>🎂 Saved in Your Cart</div>\\n<table style="width: 100%; border-collapse: collapse; margin: 20px 0;">\\n  <thead>\\n    <tr style="background-color: #f8f9fa;">\\n      <th style="padding: 12px; border-bottom: 2px solid #dee2e6; text-align: left;">Item Details</th>\\n      <th style="padding: 12px; border-bottom: 2px solid #dee2e6; text-align: center; width: 80px;">Qty</th>\\n      <th style="padding: 12px; border-bottom: 2px solid #dee2e6; text-align: right; width: 100px;">Price</th>\\n      <th style="padding: 12px; border-bottom: 2px solid #dee2e6; text-align: right; width: 100px;">Total</th>\\n    </tr>\\n  </thead>\\n  <tbody>${itemsHtml}\\n  </tbody>\\n  <tfoot>\\n    <tr>\\n      <td colspan="3" style="padding: 12px; text-align: right; font-weight: bold; border-top: 2px solid #dee2e6;">Estimated Subtotal:</td>\\n      <td style="padding: 12px; text-align: right; font-weight: bold; border-top: 2px solid #dee2e6; color: #28a745;">${formatCurrency(subtotal)}</td>\\n    </tr>\\n  </tfoot>\\n</table></div>\\n<div style="text-align: center;">\\n  <a href="https://genie.ph/cart" class="btn-primary" style="color:#ffffff !important;">✨ Return and Checkout Now</a>\\n</div><div style='background:#f8f9fa;padding:20px;border-radius:8px;margin:20px 0'><p style='margin:0;font-size:14px;color:#666'><strong>Need assistance?</strong><br>If you run into any issues checking out or have questions about customized designs, reply to this email or contact us at <strong>09089408747</strong>.</p></div><p style='text-align:center;color:#666;margin:0'>From the Genie.ph Team</p></div><div class='footer'><p>This email was sent to ${recipientEmail} because you have items in your Genie.ph cart.</p><p>© 2025 Genie.ph - Making celebrations magical, one cake at a time ✨</p></div></div></body></html>`;

const textContent = `✨ YOUR SAVED CART AT GENIE.PH ✨\\n\\nHi ${firstName},\\n\\n${introductoryCopy}\\n\\n🎂 Items in Your Cart:\\n${itemsText}\\nEstimated Subtotal: ${formatCurrency(subtotal)}\\n\\nReturn to your cart to check out here: https://genie.ph/cart\\n\\nNeed Help?\\nReply directly to this email or call us at 09089408747.\\n\\nFrom the Genie.ph Team`;

return [{
  json: {
    sendEmail: true,
    recipientEmail: recipientEmail,
    recipientName: firstName,
    subject: subject,
    htmlContent: htmlContent,
    textContent: textContent,
    userId: userData.user_id,
    emailType: emailType
  }
}];
